import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { 
    User, 
    Mail, 
    Phone, 
    Calendar, 
    MapPin, 
    GraduationCap, 
    BookOpen, 
    Target, 
