                            </div>
                            <div className="field-input-container">
                                <select
                                    id="howDidYouHear"
                                    value={currentFormData.howDidYouHear || ''}
                                    onChange={handleChange}
                                    className={`modern-select ${errors.howDidYouHear ? 'error' : ''}`}
                                    required
                                >
                                    <option value="">{t('applicationForm.fields.howDidYouHear')}</option>
                                    <option value="searchEngine">{t('applicationForm.options.howDidYouHear.searchEngine')}</option>
                                    <option value="socialMedia">{t('applicationForm.options.howDidYouHear.socialMedia')}</option>
                                    <option value="friend">{t('applicationForm.options.howDidYouHear.friend')}</option>
                                    <option value="advertisement">{t('applicationForm.options.howDidYouHear.advertisement')}</option>
                                    <option value="event">{t('applicationForm.options.howDidYouHear.event')}</option>
                                    <option value="other">{t('applicationForm.options.howDidYouHear.other')}</option>
                                </select>
                                <label className="modern-label">{t('applicationForm.fields.howDidYouHear')}</label>
                                {errors.howDidYouHear && <div className="error-message-modern">{errors.howDidYouHear}</div>}
                            </div>
                        </div>

                        <div className="form-field-modern full-width">
                            <div className="field-icon">
                                <Star className="w-5 h-5 text-orange-500" />
                            </div>
                            <div className="field-input-container">
                                <textarea
                                    id="careerGoals"
                                    value={currentFormData.careerGoals || ''}
                                    onChange={handleChange}
                                    rows="4"
                                    className="modern-textarea"
                                    placeholder={t('applicationForm.fields.careerGoals')}
                                ></textarea>
                                <label className="modern-label">{t('applicationForm.fields.careerGoals')}</label>
                            </div>
                        </div>

                        <div className="form-field-modern full-width">
                            <div className="field-icon">
                                <Sparkles className="w-5 h-5 text-orange-500" />
                            </div>
                            <div className="field-input-container">
                                <textarea
                                    id="questions"
                                    value={currentFormData.questions || ''}
                                    onChange={handleChange}
                                    rows="4"
                                    className="modern-textarea"
                                    placeholder={t('applicationForm.fields.questions')}
                                ></textarea>
                                <label className="modern-label">{t('applicationForm.fields.questions')}</label>
                            </div>
                        </div>

                        <div className="modern-checkbox-container">
                            <div className="modern-checkbox">
                                <input
                                    type="checkbox"
                                    id="application-terms"
                                    name="agreeToTerms"
                                    checked={currentFormData.agreeToTerms || false}
                                    onChange={handleChange}
                                    required
                                />
                                <div className="checkbox-checkmark">
                                    <CheckCircle className="w-5 h-5" />
                                </div>
                                <label htmlFor="application-terms" className="checkbox-label">
                                    {t('applicationForm.fields.agreeToTerms')} <a href="/terms" target="_blank" rel="noopener noreferrer" className="terms-link">{t('applicationForm.termsLink')}</a> {t('applicationForm.dataConsent')}
                                </label>
                            </div>
                            {errors.agreeToTerms && <div className="error-message-modern">{errors.agreeToTerms}</div>}
                        </div>
                    </div>
                );

            default:
                return <div className="unknown-step">{t('applicationForm.unknownStep')}</div>;
        }
    };

    return (
        <div className="application-wrapper-modern">
            {/* Background Elements */}
            <div className="background-elements">
                <div className="floating-shape shape-1"></div>
                <div className="floating-shape shape-2"></div>
                <div className="floating-shape shape-3"></div>
                <div className="floating-shape shape-4"></div>
            </div>

            <div className="form-container-modern">
                {/* Enhanced Header */}
                <div className="form-header-modern">
                    <div className={`step-icon-container ${stepInfo.bgColor}`}>
                        <div className={`step-icon-gradient bg-gradient-to-r ${stepInfo.color}`}>
                            <StepIcon className="w-8 h-8 text-white" />
                        </div>
                    </div>

                    <div className="header-content">
                        <h2 className="form-title-modern">{stepInfo.title}</h2>
                        <p className="form-description-modern">
                            {step === 0 && t('applicationForm.steps.personalInfo.description')}
                            {step === 1 && t('applicationForm.steps.education.description')}
                            {step === 2 && t('applicationForm.steps.programSelection.description')}
                            {step === 3 && t('applicationForm.steps.additionalInfo.description')}
                        </p>
                    </div>
                </div>

                {/* Enhanced Progress Bar */}
                <div className="progress-container-modern">
                    <div className="progress-steps">
                        {[0, 1, 2, 3].map((stepIndex) => (
                            <div key={stepIndex} className={`progress-step ${stepIndex <= step ? 'active' : ''}`}>
                                <div className="step-circle">
                                    {stepIndex < step ? (
                                        <CheckCircle className="w-5 h-5 text-white" />
                                    ) : (
                                        <span className="step-number">{stepIndex + 1}</span>
                                    )}
                                </div>
                                {stepIndex < 3 && <div className={`step-line ${stepIndex < step ? 'completed' : ''}`}></div>}
                            </div>
                        ))}
                    </div>
                    <div className="progress-info">
                        <span className="progress-text">{t('applicationForm.stepIndicator', { current: step + 1, total: 4 })}</span>
                        <span className="progress-percentage">{Math.round(stepInfo.progress)}%</span>
                    </div>
                </div>

                {/* Enhanced Form */}
                <form onSubmit={handleSubmit} className="application-form-modern">
                    <div className="form-content">
                        {renderFormFields()}
                    </div>

                    {/* Enhanced Action Buttons */}
                    <div className="form-actions-modern">
                        {step > 0 && (
                            <button 
                                type="button" 
                                className="btn-modern btn-secondary" 
                                onClick={onBack}
                            >
                                <ArrowLeft className="w-5 h-5" />
                                <span>{t('applicationForm.buttons.back')}</span>
                            </button>
                        )}
                        <button 
                            type="submit" 
                            className="btn-modern btn-primary"
                        >
                            <span>{step === 3 ? t('applicationForm.buttons.submit') : t('applicationForm.buttons.continue')}</span>
                            {step === 3 ? (
                                <Send className="w-5 h-5" />
                            ) : (
                                <ArrowRight className="w-5 h-5" />
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default ApplicationForm;
